      {:ok, %HTTPoison.Response{status_code: status_code, body: body}} ->
        conn
        |> put_status(status_code)
        |> json(%{error: "Request failed with status #{status_code}", body: body})

      {:error, %HTTPoison.Error{reason: reason}} ->
        conn
        |> put_status(502)
        |> json(%{error: "Failed to fetch URL", reason: inspect(reason)})
    end
  end

  def fetch(conn, _params) do
    conn
    |> put_status(400)
    |> json(%{error: "Missing required parameter: url"})
  end

  defp get_content_type(headers) do
    headers
    |> Enum.find(fn {key, _} -> String.downcase(key) == "content-type" end)
    |> case do
      {_, content_type} -> content_type
      nil -> "text/plain"
    end
  end
end